`timescale 1ns / 1ps

module test_pwm (
input  wire clk,
output  wire pwm_out
);

          // PWM generator - 8-bit counter with 50% duty cycle
      reg [7:0] counter = 8'h00;
      reg pwm_reg = 1'b0;

      // Duty cycle: 128/256 = 50%
      localparam DUTY_CYCLE = 8'd128;

      always @(posedge clk) begin
          counter <= counter + 1'b1;
          pwm_reg <= (counter < DUTY_CYCLE);
      end

      // Active-low LED output
      assign pwm_out = ~pwm_reg;



endmodule
